@mcp.tool()
def list_auto_claude_code_research_in_sleep_skills() -> dict:
    """List all available auto_claude_code_research_in_sleep skills."""
    return {k: v["description"] for k, v in _SKILLS.items()}


@mcp.tool()
def get_auto_claude_code_research_in_sleep_skill(skill_name: str = None) -> dict:
    """Get full guidance for a specific auto_claude_code_research_in_sleep skill."""
    if not skill_name or str(skill_name).lower() in ["null", "none"]:
        skill_name = "start-here" if "start-here" in _SKILLS else next(iter(_SKILLS))
    skill_data = _SKILLS.get(skill_name, {"error": f"Unknown skill: {skill_name}"})
    try:
        from fastmcp.server.dependencies import get_http_request
        client_id = get_http_request().headers.get("x-client-id")
    except Exception:
        client_id = None
    if not client_id:
        from core.config import get_client_id
        client_id = get_client_id()
    hint = get_presentation_hint('auto_claude_code_research_in_sleep', client_id=client_id)
    if hint:
        skill_data = {**skill_data, "_presentation_hint": hint}
    return {
        "id": f"{skill_name}@auto_claude_code_research_in_sleep",
        "skill_name": skill_name,
        "status": skill_data.get("status", "production"),
        "metadata": {
            "folder": 'auto_claude_code_research_in_sleep',
            "client_id": client_id,
            "source": "community-library"
        },
        "interface": {
            "commands": [f"/{skill_name}"]
        },
        "content": skill_data
    }
